    let ok = match state.protected_call(nargs, LUA_MULTRET, 0) {
        Ok(()) => true,
        Err(e) => {
            state.push(e.into_value());
            false
        }
    };
    // C: return finishpcall(L, status, 0);
    finish_pcall(state, ok, 0)
}

