    state.push(LuaValue::Int(i));
    // C: return (lua_geti(L, 1, i) == LUA_TNIL) ? 1 : 2;
    let t = state.get_i(1, i)?;
    if t == LuaType::Nil {
        Ok(1)
    } else {
        Ok(2)
    }
}

