        // C: g->panic = NULL;
        panic: None,
        // C: g->mainthread = L; — set after main thread created
        mainthread: None,
        memerrmsg: placeholder_str.clone(),
        tmname: Vec::new(),
        // C: for (i=0; i < LUA_NUMTAGS; i++) g->mt[i] = NULL;
